const chalk = require('chalk');

/**
 *
 */
class Log{

    constructor(){
    }

    /**
     *
     * @param msg
     */
    log(msg = '') {
        console.log(chalk.white(msg));
    }

    /**
     *
     * @param msg
     */
    warn(msg = '') {
        console.log(chalk.yellow(`[WARNING] ${msg}`));
    }

    /**
     *
     * @param msg
     */
    error(msg = '') {
        console.log(chalk.red(`[ERROR] ${msg}`));
    }

    /**
     *
     * @param msg
     */
    throw(msg = ''){
        throw new Error(`[ERROR] ${msg}`);
    }
}

module.exports = Log;